using Microsoft.UI.Xaml.Data;

namespace Invoice.Helpers
{
    public class DateTimeFormatter : IValueConverter
    {
        public object Convert(object value, Type targetType, object parameter, string language)
        {
            if (value is DateTime dt)
            {
                // Use the parameter as the format string (e.g., "dd/MM/yyyy"), or default to "dd/MM/yyyy"
                string format = parameter as string ?? "dd/MM/yyyy";
                return dt.ToString(format);
            }
            return value;
        }

        public object ConvertBack(object value, Type targetType, object parameter, string language)
        {
            throw new NotImplementedException();
        }
    }
}

using Microsoft.UI.Xaml;
using Microsoft.UI.Xaml.Data;

namespace Invoice.Helpers;

public class EnumToBooleanConverter : IValueConverter
{
    public EnumToBooleanConverter()
    {
    }

    public object Convert(object value, Type targetType, object parameter, string language)
    {
        if (parameter is string enumString)
        {
            if (!Enum.IsDefined(typeof(ElementTheme), value))
            {
                throw new ArgumentException("ExceptionEnumToBooleanConverterValueMustBeAnEnum");
            }

            var enumValue = Enum.Parse(typeof(ElementTheme), enumString);

            return enumValue.Equals(value);
        }

        throw new ArgumentException("ExceptionEnumToBooleanConverterParameterMustBeAnEnumName");
    }

    public object ConvertBack(object value, Type targetType, object parameter, string language)
    {
        if (parameter is string enumString)
        {
            return Enum.Parse(typeof(ElementTheme), enumString);
        }

        throw new ArgumentException("ExceptionEnumToBooleanConverterParameterMustBeAnEnumName");
    }
}

using Microsoft.UI.Xaml.Data;

namespace Invoice.Helpers;

public class IntToStringConverter : IValueConverter
{    
    public object Convert(object value, Type targetType, object parameter, string language)
    {
        if (value is int intValue)
        {
            return intValue == 0 ? "" : intValue.ToString(); // Hoặc trả về intValue.ToString() luôn nếu muốn hiện số 0
        }
        return "";
    }    
    public object ConvertBack(object value, Type targetType, object parameter, string language)
    {
        string strValue = value as string;
        if (string.IsNullOrEmpty(strValue))
        {
            return 0; // Nếu xóa hết chữ thì trả về 0 (để không bị lỗi)
        }

        if (int.TryParse(strValue, out int result))
        {
            return result;
        }

        return 0; // Nhập linh tinh cũng trả về 0
    }
}

using System.Globalization;
using Microsoft.UI.Xaml.Data;

namespace Invoice.Helpers;

public class DoubleToStringConverter : IValueConverter
{
    public object Convert(object value, Type targetType, object parameter, string language)
    {
        if (value is double d)
        {           
            string format = parameter as string ?? "N0";            
            return d.ToString(format, CultureInfo.CurrentCulture);
        }
        if (value is int i)
        {
            return i.ToString("N0", new CultureInfo("vi-VN"));
        }

        if (value is long l)
        {
            return l.ToString("N0", new CultureInfo("vi-VN"));
        }
        return value;
    }

    public object ConvertBack(object value, Type targetType, object parameter, string language)
    {
        throw new NotImplementedException();
    }
}

