    partial void OnAmountChanged(int value)
    {
        System.Diagnostics.Debug.WriteLine($"[DEBUG] Đang nhập: {value} | Giới hạn MaxStock: {MaxStock} - OnAmountChanged");
        if (MaxStock <= 0)
        {
            if (value != 0) Amount = 0;
            return;
        }

        if (value > MaxStock)
        {
            Amount = MaxStock;
            return;
        }

        if (value <= 0)
        {
            Amount = 1;
